
const HTML = "<!DOCTYPE html>\n<html lang=\"en\">\n<head>\n  <meta charset=\"UTF-8\">\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n  <title>BG Vanish — Remove Image Backgrounds Instantly</title>\n  <meta name=\"description\" content=\"Remove image backgrounds in seconds. Free, fast, no signup required.\">\n  <script src=\"https://cdn.tailwindcss.com\"></script>\n  <style>\n    @import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700;800&display=swap');\n    body { font-family: 'Inter', sans-serif; }\n    .gradient-bg { background: linear-gradient(135deg, #667eea 0%, #764ba2 100%); }\n    .glass { background: rgba(255,255,255,0.1); backdrop-filter: blur(20px); border: 1px solid rgba(255,255,255,0.2); }\n    .drop-zone { border: 2px dashed rgba(255,255,255,0.4); transition: all 0.3s ease; }\n    .drop-zone:hover, .drop-zone.drag-over { border-color: rgba(255,255,255,0.8); background: rgba(255,255,255,0.15); transform: scale(1.01); }\n    .checker-bg {\n      background-image: linear-gradient(45deg, #ccc 25%, transparent 25%), linear-gradient(-45deg, #ccc 25%, transparent 25%),\n        linear-gradient(45deg, transparent 75%, #ccc 75%), linear-gradient(-45deg, transparent 75%, #ccc 75%);\n      background-size: 16px 16px; background-position: 0 0, 0 8px, 8px -8px, -8px 0px;\n    }\n    @keyframes spin { to { transform: rotate(360deg); } }\n    .spinner { width: 40px; height: 40px; border: 3px solid rgba(255,255,255,0.2); border-top-color: white; border-radius: 50%; animation: spin 0.8s linear infinite; }\n    @keyframes pulse-glow { 0%,100%{box-shadow:0 0 20px rgba(102,126,234,0.3)} 50%{box-shadow:0 0 40px rgba(118,75,162,0.5)} }\n    .glow { animation: pulse-glow 2s ease-in-out infinite; }\n    .fade-in { animation: fadeIn 0.5s ease-out; }\n    @keyframes fadeIn { from{opacity:0;transform:translateY(10px)} to{opacity:1;transform:translateY(0)} }\n    input[type=\"color\"] { -webkit-appearance:none; border:none; width:40px; height:40px; border-radius:50%; cursor:pointer; overflow:hidden; }\n    input[type=\"color\"]::-webkit-color-swatch-wrapper { padding:0; }\n    input[type=\"color\"]::-webkit-color-swatch { border:2px solid rgba(255,255,255,0.5); border-radius:50%; }\n    .thumb { transition: all 0.2s; }\n    .thumb:hover { transform: scale(1.05); }\n    .zoom-container { position:relative; overflow:hidden; cursor:zoom-in; }\n    .zoom-container.zoomed { cursor:zoom-out; }\n    .zoom-overlay { position:absolute; inset:0; overflow:hidden; }\n    .zoom-container.zoomed .zoom-overlay img { transform: scale(2); transform-origin: var(--zx, center) var(--zy, center); }\n    .zoom-hint { position:absolute; bottom:8px; right:8px; background:rgba(0,0,0,0.6); color:#fff; font-size:11px; padding:2px 8px; border-radius:4px; opacity:0; transition:opacity 0.2s; pointer-events:none; }\n    .zoom-container:hover .zoom-hint { opacity:1; }\n    .timeout-msg { color: #fca5a5; font-size: 12px; margin-top: 4px; }\n    .google-btn { display:inline-flex; align-items:center; gap:8px; padding:8px 16px; background:#fff; color:#333; border-radius:8px; font-size:14px; font-weight:500; cursor:pointer; border:none; transition:opacity 0.2s; }\n    .google-btn:hover { opacity:0.9; }\n    .google-btn svg { width:18px; height:18px; }\n    .user-avatar { width:32px; height:32px; border-radius:50%; border:2px solid rgba(255,255,255,0.5); cursor:pointer; }\n    .user-menu { position:absolute; right:0; top:40px; background:rgba(30,20,60,0.95); backdrop-filter:blur(20px); border:1px solid rgba(255,255,255,0.15); border-radius:12px; padding:8px; min-width:180px; z-index:50; }\n    .user-menu button { display:flex; align-items:center; gap:8px; width:100%; padding:8px 12px; border:none; background:transparent; color:white; font-size:13px; cursor:pointer; border-radius:8px; text-align:left; }\n    .user-menu button:hover { background:rgba(255,255,255,0.1); }\n    .login-banner { background:rgba(255,255,255,0.1); border:1px solid rgba(255,255,255,0.2); border-radius:12px; padding:16px; text-align:center; margin-bottom:16px; }\n    .login-banner p { margin:8px 0 12px; font-size:14px; color:rgba(255,255,255,0.7); }\n    .logged-in-badge { display:inline-flex; align-items:center; gap:6px; padding:4px 12px; background:rgba(34,197,94,0.2); border:1px solid rgba(34,197,94,0.4); border-radius:20px; font-size:12px; color:#86efac; }\n  </style>\n</head>\n<body class=\"gradient-bg min-h-screen text-white\">\n\n  <header class=\"py-6 px-4\">\n    <div class=\"max-w-5xl mx-auto flex items-center justify-between\">\n      <div class=\"flex items-center gap-2\">\n        <div class=\"w-10 h-10 rounded-xl bg-white/20 flex items-center justify-center text-xl\">✨</div>\n        <span class=\"text-xl font-bold\">BG Vanish</span>\n      </div>\n      <div id=\"userSection\">\n        <!-- Will be populated by JS -->\n      </div>\n      <div id=\"counter\" class=\"text-sm text-white/70\"></div>\n    </div>\n  </header>\n\n  <main class=\"max-w-5xl mx-auto px-4 pb-20\">\n    <section class=\"text-center py-10\">\n      <h1 class=\"text-4xl md:text-6xl font-extrabold mb-4 leading-tight\">\n        Remove Any Background<br>\n        <span class=\"text-transparent bg-clip-text bg-gradient-to-r from-yellow-200 to-pink-200\">In Seconds</span>\n      </h1>\n      <p class=\"text-lg text-white/70 max-w-xl mx-auto\">\n        Drop your image, get a clean cutout. No signup, no watermark. Powered by AI.\n      </p>\n    </section>\n\n    <!-- Login Section -->\n    <div id=\"loginSection\" class=\"mb-8\">\n      <!-- Will be populated by JS -->\n    </div>\n\n    <section id=\"uploadSection\" class=\"mb-8\">\n      <div id=\"dropZone\" class=\"drop-zone rounded-2xl p-12 text-center cursor-pointer glass glow\">\n        <div class=\"flex flex-col items-center gap-4\">\n          <div class=\"text-6xl\">🖼️</div>\n          <div>\n            <p class=\"text-lg font-semibold\">Drop your image here</p>\n            <p class=\"text-sm text-white/60 mt-1\">or click to browse · PNG, JPG, WebP up to 10MB · max 5 images</p>\n          </div>\n          <label class=\"px-6 py-2.5 bg-white/20 hover:bg-white/30 rounded-lg font-medium cursor-pointer transition\">\n            Choose Files\n            <input type=\"file\" id=\"fileInput\" accept=\"image/png,image/jpeg,image/webp\" multiple class=\"hidden\">\n          </label>\n        </div>\n      </div>\n    </section>\n\n    <section id=\"queueSection\" class=\"hidden mb-8 fade-in\">\n      <div class=\"flex items-center justify-between mb-4\">\n        <h2 class=\"text-lg font-semibold\">Queue</h2>\n        <button id=\"clearAllBtn\" class=\"text-sm text-white/60 hover:text-white transition\">Clear All</button>\n      </div>\n      <div id=\"queue\" class=\"flex gap-3 overflow-x-auto pb-2\"></div>\n    </section>\n\n    <section id=\"resultsSection\" class=\"hidden fade-in\">\n      <div id=\"results\" class=\"grid gap-6\"></div>\n    </section>\n\n    <div id=\"limitModal\" class=\"hidden fixed inset-0 bg-black/60 flex items-center justify-center z-50 p-4\">\n      <div class=\"glass rounded-2xl p-8 max-w-sm w-full text-center\">\n        <div class=\"text-4xl mb-3\">🚫</div>\n        <h3 class=\"text-xl font-bold mb-2\">Daily Limit Reached</h3>\n        <p class=\"text-white/70 text-sm mb-6\">\n          You've used all <span id=\"limitCount\">5</span> free removals today.<br>Come back tomorrow or upgrade for unlimited access!\n        </p>\n        <button onclick=\"document.getElementById('limitModal').classList.add('hidden')\"\n          class=\"px-6 py-2 bg-white/20 hover:bg-white/30 rounded-lg font-medium transition\">Got it</button>\n      </div>\n    </div>\n\n    <section class=\"mt-12 text-center\">\n      <div class=\"glass rounded-2xl p-6 inline-block\">\n        <p class=\"text-sm text-white/60\">Need more? <span class=\"text-yellow-200 font-semibold\">API access</span> available for developers →</p>\n      </div>\n    </section>\n  </main>\n\n  <footer class=\"py-6 text-center text-xs text-white/40\">\n    <p>BG Vanish · Powered by Remove.bg API · No data stored</p>\n  </footer>\n\n  <script>\n    const FREE_LIMIT = 5;\n    const REQUEST_TIMEOUT = 30000; // 30 seconds\n    const state = { queue: [], maxConcurrent: 2 };\n\n    // --- Google OAuth ---\n    const GOOGLE_CLIENT_ID = '480367987155-k6bnrnt7trj6pekeo36fcipnlr0o1c18.apps.googleusercontent.com';\n    const LOGGED_IN_LIMIT = 20; // logged-in users get more\n    let currentUser = null;\n\n    async function checkAuth() {\n      try {\n        const res = await fetch('/api/auth/me');\n        if (res.ok) {\n          currentUser = await res.json();\n          onLogin();\n        } else {\n          onLogout();\n        }\n      } catch { onLogout(); }\n    }\n\n    function onLogin() {\n      const sec = document.getElementById('userSection');\n      sec.style.position = 'relative';\n      sec.innerHTML = `\n        <div class=\"flex items-center gap-3\">\n          <div id=\"userAvatar\" class=\"user-avatar\" onclick=\"document.getElementById('userMenu').classList.toggle('hidden')\">\n            <img src=\"${currentUser.picture}\" style=\"width:100%;height:100%;border-radius:50%;object-fit:cover\" onerror=\"this.style.display='none';this.parentElement.textContent='${(currentUser.name||'U')[0]}'\">\n          </div>\n          <div id=\"userMenu\" class=\"user-menu hidden\">\n            <div style=\"padding:8px 12px;border-bottom:1px solid rgba(255,255,255,0.1);margin-bottom:4px\">\n              <div style=\"font-size:14px;font-weight:600\">${currentUser.name}</div>\n              <div style=\"font-size:11px;color:rgba(255,255,255,0.5)\">${currentUser.email}</div>\n            </div>\n            <button onclick=\"logout()\">🚪 Sign out</button>\n          </div>\n        </div>`;\n      // Update login section\n      const loginSec = document.getElementById('loginSection');\n      loginSec.innerHTML = `<div class=\"logged-in-badge\">✓ Signed in as ${currentUser.name} · ${LOGGED_IN_LIMIT} images/day</div>`;\n      // Update free limit for logged-in users\n      state.freeLimit = LOGGED_IN_LIMIT;\n      updateCounter();\n    }\n\n    function onLogout() {\n      const sec = document.getElementById('userSection');\n      sec.innerHTML = `\n        <button class=\"google-btn\" onclick=\"loginWithGoogle()\">\n          <svg viewBox=\"0 0 24 24\"><path fill=\"#4285F4\" d=\"M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92a5.06 5.06 0 0 1-2.2 3.32v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.1z\"/><path fill=\"#34A853\" d=\"M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z\"/><path fill=\"#FBBC05\" d=\"M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z\"/><path fill=\"#EA4335\" d=\"M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z\"/></svg>\n          Sign in with Google\n        </button>`;\n      const loginSec = document.getElementById('loginSection');\n      loginSec.innerHTML = `\n        <div class=\"login-banner\">\n          <p>🎁 Sign in to get <strong>20 free images/day</strong> instead of 5</p>\n        </div>`;\n      state.freeLimit = FREE_LIMIT;\n      currentUser = null;\n    }\n\n    function loginWithGoogle() {\n      const redirectUri = window.location.origin + '/api/auth/callback';\n      const scope = 'openid email profile';\n      const url = `https://accounts.google.com/o/oauth2/v2/auth?client_id=${GOOGLE_CLIENT_ID}&redirect_uri=${encodeURIComponent(redirectUri)}&response_type=code&scope=${encodeURIComponent(scope)}&access_type=offline&prompt=consent`;\n      window.location.href = url;\n    }\n\n    async function logout() {\n      await fetch('/api/auth/logout', { method: 'POST' });\n      document.getElementById('userMenu')?.classList.add('hidden');\n      onLogout();\n      updateCounter();\n    }\n\n    // Update getUsage to use dynamic limit\n    function getFreeLimit() { return state.freeLimit || FREE_LIMIT; }\n\n    // --- Daily limit ---\n    function getUsage() {\n      const today = new Date().toISOString().slice(0, 10);\n      const key = currentUser ? 'bgv_usage_auth' : 'bgv_usage';\n      const data = JSON.parse(localStorage.getItem(key) || '{}');\n      return data.date === today ? data : { date: today, count: 0 };\n    }\n    function incrementUsage() {\n      const u = getUsage(); u.count++;\n      const key = currentUser ? 'bgv_usage_auth' : 'bgv_usage';\n      localStorage.setItem(key, JSON.stringify(u));\n      updateCounter();\n    }\n    function updateCounter() {\n      const u = getUsage(), limit = getFreeLimit(), r = limit - u.count;\n      document.getElementById('counter').textContent = u.count > 0 ? `🆓 ${Math.max(0,r)}/${limit} today` : '';\n    }\n\n    // Init auth on page load\n    state.freeLimit = FREE_LIMIT;\n    updateCounter();\n\n    // Check if we just came back from OAuth callback\n    if (window.location.search.includes('auth=success')) {\n      window.history.replaceState({}, '', '/');\n    }\n    checkAuth();\n\n    // --- Drag & Drop ---\n    const dropZone = document.getElementById('dropZone');\n    const fileInput = document.getElementById('fileInput');\n\n    dropZone.addEventListener('dragover', (e) => { e.preventDefault(); dropZone.classList.add('drag-over'); });\n    dropZone.addEventListener('dragleave', () => dropZone.classList.remove('drag-over'));\n    dropZone.addEventListener('drop', (e) => {\n      e.preventDefault(); dropZone.classList.remove('drag-over');\n      handleFiles(e.dataTransfer.files);\n    });\n    dropZone.addEventListener('click', (e) => {\n      if (e.target.tagName !== 'INPUT' && e.target.tagName !== 'LABEL') fileInput.click();\n    });\n    fileInput.addEventListener('change', (e) => handleFiles(e.target.files));\n\n    document.getElementById('clearAllBtn').addEventListener('click', () => {\n      state.queue.forEach(i => { URL.revokeObjectURL(i.originalUrl); if (i.resultUrl) URL.revokeObjectURL(i.resultUrl); });\n      state.queue = [];\n      render();\n    });\n\n    function handleFiles(files) {\n      const arr = Array.from(files);\n      const rem = FREE_LIMIT - getUsage().count;\n      const ok = arr.filter(f => f.type.startsWith('image/')).slice(0, Math.min(5 - state.queue.length, rem));\n      if (!ok.length) {\n        if (getUsage().count >= FREE_LIMIT) {\n          document.getElementById('limitCount').textContent = FREE_LIMIT;\n          document.getElementById('limitModal').classList.remove('hidden');\n        }\n        return;\n      }\n      ok.forEach(file => {\n        state.queue.push({\n          id: Math.random().toString(36).slice(2),\n          file,\n          originalUrl: URL.createObjectURL(file),\n          resultUrl: null,\n          status: 'pending', // pending | processing | done | error\n          error: null,\n        });\n      });\n      render();\n      processQueue();\n    }\n\n    // --- Render ---\n    function render() {\n      const qs = document.getElementById('queueSection');\n      const qe = document.getElementById('queue');\n      const rs = document.getElementById('resultsSection');\n      const re = document.getElementById('results');\n\n      if (!state.queue.length) { qs.classList.add('hidden'); rs.classList.add('hidden'); return; }\n\n      qs.classList.remove('hidden');\n      qe.innerHTML = state.queue.map(item => `\n        <div class=\"thumb flex-shrink-0 w-20 h-20 rounded-lg overflow-hidden relative\" data-id=\"${item.id}\">\n          <img src=\"${item.originalUrl}\" class=\"w-full h-full object-cover\">\n          ${item.status === 'processing' ? '<div class=\"absolute inset-0 bg-black/50 flex items-center justify-center\"><div class=\"spinner\" style=\"width:24px;height:24px;border-width:2px\"></div></div>' : ''}\n          ${item.status === 'done' ? '<div class=\"absolute bottom-0 inset-x-0 bg-green-500 text-center text-xs py-0.5\">✓</div>' : ''}\n          ${item.status === 'error' ? '<div class=\"absolute bottom-0 inset-x-0 bg-red-500 text-center text-xs py-0.5\">✗</div>' : ''}\n        </div>\n      `).join('');\n\n      const done = state.queue.filter(i => i.status === 'done' || i.status === 'error');\n      if (!done.length) { rs.classList.add('hidden'); return; }\n\n      rs.classList.remove('hidden');\n      re.innerHTML = done.map(renderResult).join('');\n\n      // Event listeners\n      re.querySelectorAll('.download-btn').forEach(btn => {\n        btn.addEventListener('click', () => {\n          const id = btn.dataset.id;\n          const transparent = btn.dataset.transparent === 'true';\n          const item = state.queue.find(i => i.id === id);\n          if (item?.resultUrl) downloadResult(item, transparent);\n        });\n      });\n      re.querySelectorAll('.color-picker').forEach(input => {\n        input.addEventListener('input', (e) => {\n          const item = state.queue.find(i => i.id === input.dataset.id);\n          if (item?.resultUrl) {\n            const el = document.getElementById('result-' + item.id);\n            if (el) el.style.backgroundColor = e.target.value;\n          }\n        });\n      });\n      re.querySelectorAll('.bg-preset').forEach(btn => {\n        btn.addEventListener('click', () => {\n          const el = document.getElementById('result-' + btn.dataset.id);\n          if (el) el.style.backgroundColor = btn.dataset.color === 'transparent' ? '' : btn.dataset.color;\n        });\n      });\n      // Zoom\n      re.querySelectorAll('.zoom-container').forEach(container => {\n        container.addEventListener('click', (e) => {\n          const rect = container.getBoundingClientRect();\n          const x = ((e.clientX - rect.left) / rect.width * 100).toFixed(1);\n          const y = ((e.clientY - rect.top) / rect.height * 100).toFixed(1);\n          container.style.setProperty('--zx', x + '%');\n          container.style.setProperty('--zy', y + '%');\n          container.classList.toggle('zoomed');\n        });\n      });\n    }\n\n    function renderResult(item) {\n      if (item.status === 'error') {\n        return `\n          <div class=\"glass rounded-2xl p-6 fade-in text-center py-8\">\n            <div class=\"text-3xl mb-2\">😕</div>\n            <p class=\"text-red-300 text-sm\">${item.error || 'Processing failed'}</p>\n          </div>`;\n      }\n\n      return `\n        <div class=\"glass rounded-2xl p-6 fade-in\">\n          <div class=\"flex flex-col md:flex-row gap-6\">\n            <div class=\"flex-1 text-center\">\n              <p class=\"text-xs text-white/50 mb-2 uppercase tracking-wide\">Original</p>\n              <div class=\"zoom-container rounded-xl overflow-hidden bg-black/20\" style=\"height:240px\">\n                <div class=\"zoom-overlay w-full h-full flex items-center justify-center\">\n                  <img src=\"${item.originalUrl}\" class=\"max-h-full object-contain\" style=\"transition:transform 0.2s\">\n                </div>\n                <span class=\"zoom-hint\">Click to zoom</span>\n              </div>\n            </div>\n            <div class=\"flex items-center text-2xl\">→</div>\n            <div class=\"flex-1 text-center\">\n              <p class=\"text-xs text-white/50 mb-2 uppercase tracking-wide\">Result</p>\n              <div id=\"result-${item.id}\" class=\"zoom-container checker-bg rounded-xl overflow-hidden\" style=\"height:240px\">\n                <div class=\"zoom-overlay w-full h-full flex items-center justify-center\">\n                  <img src=\"${item.resultUrl}\" class=\"max-h-full object-contain\" style=\"transition:transform 0.2s\">\n                </div>\n                <span class=\"zoom-hint\">Click to zoom</span>\n              </div>\n            </div>\n          </div>\n          <div class=\"mt-4 flex flex-wrap items-center justify-between gap-3\">\n            <div class=\"flex items-center gap-2\">\n              <span class=\"text-xs text-white/50\">BG:</span>\n              <button class=\"bg-preset w-7 h-7 rounded-full border-2 border-white/30 checker-bg\" data-id=\"${item.id}\" data-color=\"transparent\" title=\"Transparent\"></button>\n              <button class=\"bg-preset w-7 h-7 rounded-full border-2 border-white/30 bg-white\" data-id=\"${item.id}\" data-color=\"#ffffff\" title=\"White\"></button>\n              <button class=\"bg-preset w-7 h-7 rounded-full border-2 border-white/30 bg-black\" data-id=\"${item.id}\" data-color=\"#000000\" title=\"Black\"></button>\n              <button class=\"bg-preset w-7 h-7 rounded-full border-2 border-white/30 bg-red-500\" data-id=\"${item.id}\" data-color=\"#ef4444\" title=\"Red\"></button>\n              <button class=\"bg-preset w-7 h-7 rounded-full border-2 border-white/30 bg-blue-500\" data-id=\"${item.id}\" data-color=\"#3b82f6\" title=\"Blue\"></button>\n              <button class=\"bg-preset w-7 h-7 rounded-full border-2 border-white/30 bg-green-500\" data-id=\"${item.id}\" data-color=\"#22c55e\" title=\"Green\"></button>\n              <input type=\"color\" class=\"color-picker\" data-id=\"${item.id}\" value=\"#8b5cf6\" title=\"Custom color\">\n            </div>\n            <div class=\"flex gap-2\">\n              <button class=\"download-btn px-4 py-2 bg-white text-purple-700 rounded-lg font-semibold text-sm hover:bg-yellow-200 transition\" data-id=\"${item.id}\" data-transparent=\"true\">⬇ Transparent</button>\n              <button class=\"download-btn px-4 py-2 bg-white/20 text-white rounded-lg font-semibold text-sm hover:bg-white/30 transition\" data-id=\"${item.id}\" data-transparent=\"false\">⬇ With BG</button>\n            </div>\n          </div>\n        </div>`;\n    }\n\n    function downloadResult(item, transparent) {\n      const canvas = document.createElement('canvas');\n      const ctx = canvas.getContext('2d');\n      const img = new Image();\n      img.onload = () => {\n        canvas.width = img.width;\n        canvas.height = img.height;\n        if (!transparent) {\n          const el = document.getElementById('result-' + item.id);\n          const bg = el?.style.backgroundColor || '';\n          if (bg) { ctx.fillStyle = bg; ctx.fillRect(0, 0, canvas.width, canvas.height); }\n        }\n        ctx.drawImage(img, 0, 0);\n        const suffix = transparent ? '-no-bg' : '-bg';\n        canvas.toBlob(blob => {\n          const url = URL.createObjectURL(blob);\n          const a = document.createElement('a');\n          a.href = url;\n          a.download = item.file.name.replace(/\\.[^.]+$/, '') + suffix + '.png';\n          a.click();\n          URL.revokeObjectURL(url);\n        }, 'image/png');\n      };\n      img.src = item.resultUrl;\n    }\n\n    // --- Processing with timeout ---\n    async function processQueue() {\n      while (true) {\n        const pending = state.queue.filter(i => i.status === 'pending');\n        const processing = state.queue.filter(i => i.status === 'processing').length;\n        if (!pending.length) break;\n        if (processing >= state.maxConcurrent) { await new Promise(r => setTimeout(r, 500)); continue; }\n\n        const item = pending[0];\n        item.status = 'processing';\n        render();\n\n        try {\n          const controller = new AbortController();\n          const timer = setTimeout(() => controller.abort(), REQUEST_TIMEOUT);\n\n          const fd = new FormData();\n          fd.append('image', item.file);\n          fd.append('size', 'auto');\n\n          const res = await fetch('/api/remove-bg', { method: 'POST', body: fd, signal: controller.signal });\n          clearTimeout(timer);\n\n          if (!res.ok) {\n            const err = await res.json().catch(() => ({ error: 'Unknown error' }));\n            throw new Error(err.error || 'HTTP ' + res.status);\n          }\n\n          const blob = await res.blob();\n          item.resultUrl = URL.createObjectURL(blob);\n          item.status = 'done';\n          incrementUsage();\n        } catch (err) {\n          item.status = 'error';\n          if (err.name === 'AbortError') {\n            item.error = 'Processing timed out (30s). Please try a smaller image.';\n          } else {\n            item.error = err.message;\n          }\n        }\n        render();\n      }\n    }\n\n    // Paste\n    document.addEventListener('paste', (e) => {\n      const items = e.clipboardData?.items;\n      if (!items) return;\n      const files = [];\n      for (const i of items) {\n        if (i.kind === 'file' && i.type.startsWith('image/')) files.push(i.getAsFile());\n      }\n      if (files.length) handleFiles(files);\n    });\n  </script>\n</body>\n</html>\n";

const COOKIE_SECRET = 'bg-vanish-session-2026';

function parseCookie(h) {
  const c = {};
  if (!h) return c;
  h.split(';').forEach(p => { const [k,v] = p.trim().split('='); if(k) c[k]=v; });
  return c;
}
function setCookie(res, name, val, maxAge=604800) {
  res.headers.append('Set-Cookie', `${name}=${val}; Path=/; HttpOnly; SameSite=Lax; Max-Age=${maxAge}`);
}
function clearCookie(res, name) {
  res.headers.append('Set-Cookie', `${name}=; Path=/; HttpOnly; SameSite=Lax; Max-Age=0`);
}

async function handleAuthCallback(request, env) {
  const url = new URL(request.url);
  const code = url.searchParams.get('code');
  if (!code) return json({error:'Missing code'}, 400);
  const redirectUri = url.protocol + '//' + url.host + '/api/auth/callback';
  try {
    const clientId = env.GOOGLE_CLIENT_ID || '480367987155-k6bnrnt7trj6pekeo36fcipnlr0o1c18.apps.googleusercontent.com';
    const clientSecret = env.GOOGLE_CLIENT_SECRET || '';
    const tokenRes = await fetch('https://oauth2.googleapis.com/token', {
      method: 'POST',
      headers: {'Content-Type': 'application/x-www-form-urlencoded'},
      body: new URLSearchParams({code, client_id: clientId, client_secret: clientSecret, redirect_uri: redirectUri, grant_type: 'authorization_code'}),
    });
    const td = await tokenRes.json();
    if (!tokenRes.ok) throw new Error(td.error_description || 'Token exchange failed');
    const userRes = await fetch('https://www.googleapis.com/oauth2/v2/userinfo', {headers: {Authorization: 'Bearer ' + td.access_token}});
    const ud = await userRes.json();
    const sessionData = JSON.stringify({sub:ud.id, name:ud.name, email:ud.email, picture:ud.picture, exp:Date.now()+604800000});
    const sessionToken = Buffer.from(sessionData).toString('base64url') + '.' + require('crypto').createHash('sha256').update(COOKIE_SECRET + sessionData).digest('base64url').slice(0,32);
    const res = new Response(null, {status: 302, headers: new Headers({'Location': '/?auth=success'})});
    setCookie(res, 'session', sessionToken, 604800);
    return res;
  } catch(e) { return json({error:e.message}, 500); }
}

function handleAuthMe(request) {
  const session = parseCookie(request.headers.get('cookie'));
  const token = session.session;
  if (!token) return json({error:'Not authenticated'}, 401);
  try {
    const [pb, sig] = token.split('.');
    const payload = JSON.parse(Buffer.from(pb, 'base64url').toString());
    if (payload.exp < Date.now()) { return json({error:'Session expired'}, 401); }
    const expectedSig = require('crypto').createHash('sha256').update(COOKIE_SECRET + JSON.stringify(payload)).digest('base64url').slice(0,32);
    if (sig !== expectedSig) return json({error:'Invalid session'}, 401);
    return json({id:payload.sub, name:payload.name, email:payload.email, picture:payload.picture});
  } catch(e) { return json({error:'Invalid session'}, 401); }
}

function handleLogout(request) {
  const res = new Response(JSON.stringify({success:true}), {headers:{'Content-Type':'application/json'}});
  clearCookie(res, 'session');
  return res;
}

async function handleRemoveBg(request, env) {
  const apiKey = env.REMOVE_BG_API_KEY;
  if (!apiKey) return json({error:'API key not configured'}, 500);
  const maxSize = parseInt(env.MAX_FILE_SIZE || '10485760', 10);
  try {
    const formData = await request.formData();
    const imageFile = formData.get('image');
    const size = formData.get('size') || 'auto';
    if (!imageFile) return json({error:'No image provided'}, 400);
    if (imageFile.size > maxSize) return json({error:'File too large. Max '+(maxSize/1024/1024)+'MB'}, 400);
    const bg = new FormData();
    bg.append('image_file', imageFile, imageFile.name);
    bg.append('size', size);
    const res = await fetch('https://api.remove.bg/v1.0/removebg', {method:'POST', headers:{'X-Api-Key':apiKey}, body:bg});
    if (!res.ok) {
      const txt = await res.text();
      let msg;
      try { const j = JSON.parse(txt); msg = (j.errors&&j.errors[0]&&j.errors[0].title)||txt; } catch(e) { msg='Remove.bg error: '+res.status; }
      if (res.status === 402) return json({error:'API credits exhausted.'}, 503);
      return json({error:msg}, res.status);
    }
    return new Response(await res.arrayBuffer(), {headers:{'Content-Type':'image/png','Cache-Control':'no-store'}});
  } catch(e) { return json({error:e.message||'Server error'}, 500); }
}

function json(data, status) { return new Response(JSON.stringify(data), {status, headers:{'Content-Type':'application/json'}}); }

export default {
  async fetch(request, env) {
    if (request.method === 'OPTIONS') return new Response(null, {headers:{'Access-Control-Allow-Origin':'*','Access-Control-Allow-Methods':'GET,POST,OPTIONS','Access-Control-Allow-Headers':'Content-Type'}});
    const url = new URL(request.url);
    if (url.pathname === '/' || url.pathname === '/index.html') return new Response(HTML, {headers:{'Content-Type':'text/html;charset=utf-8'}});
    if (url.pathname === '/api/remove-bg' && request.method === 'POST') return handleRemoveBg(request, env);
    if (url.pathname === '/api/auth/callback') return handleAuthCallback(request, env);
    if (url.pathname === '/api/auth/me') return handleAuthMe(request);
    if (url.pathname === '/api/auth/logout' && request.method === 'POST') return handleLogout(request);
    if (url.pathname === '/api/health') return Response.json({status:'ok'});
    return new Response('Not found', {status:404});
  }
};
